/**
 * State of one scalar level and rate alpha-beta channel.
 */
typedef struct SidereonAlphaBetaState {
    /**
     * Level estimate, in caller-chosen units.
     */
    double level;
    /**
     * Rate estimate, in caller-chosen units per second.
     */
    double rate;
} SidereonAlphaBetaState;

/**
 * Alpha-beta gain set for one scalar channel.
 */
typedef struct SidereonAlphaBetaGains {
    /**
     * Level gain alpha.
     */
    double alpha;
    /**
     * Rate gain beta. The update applies beta * innovation / dt.
     */
    double beta;
} SidereonAlphaBetaGains;

/**
 * One alpha-beta predict and update result.
 */
typedef struct SidereonAlphaBetaStep {
    /**
     * Predicted state before applying the measurement.
     */
    struct SidereonAlphaBetaState predicted;
    /**
     * Updated state after applying the measurement.
     */
    struct SidereonAlphaBetaState updated;
    /**
     * Measurement innovation, measurement minus predicted level.
     */
    double innovation;
} SidereonAlphaBetaStep;

/**
 * An ECEF line-of-sight unit vector from the receiver toward a satellite.
 *
 * The design-matrix row this contributes is `[-e_x, -e_y, -e_z, 1]`. The
 * vector must be unit length to the engine's tolerance.
 */
typedef struct SidereonLineOfSight {
    /**
     * ECEF X component of the unit line-of-sight vector.
     */
    double e_x;
    /**
     * ECEF Y component of the unit line-of-sight vector.
     */
    double e_y;
    /**
     * ECEF Z component of the unit line-of-sight vector.
     */
    double e_z;
} SidereonLineOfSight;

/**
 * One satellite row in an ARAIM geometry snapshot.
 */
typedef struct SidereonAraimRow {
    /**
     * Null-terminated satellite token.
     */
    const char *sat_id;
    /**
     * Receiver-to-satellite ECEF unit line of sight.
     */
    struct SidereonLineOfSight line_of_sight;
    /**
     * GNSS system as SidereonGnssSystem.
     */
    uint32_t system;
    /**
     * Elevation angle at the receiver, radians.
     */
    double elevation_rad;
} SidereonAraimRow;

/**
 * Geodetic receiver position in radians and meters.
 */
typedef struct SidereonGeodetic {
    /**
     * Geodetic latitude in radians.
     */
    double lat_rad;
    /**
     * Geodetic longitude in radians.
     */
    double lon_rad;
    /**
     * Ellipsoidal height above WGS84 in meters.
     */
    double height_m;
} SidereonGeodetic;

/**
 * ARAIM geometry input. `rows` and `clock_systems` are caller-owned arrays.
 */
typedef struct SidereonAraimGeometry {
    /**
     * Satellite rows.
     */
    const struct SidereonAraimRow *rows;
    /**
     * Number of satellite rows.
     */
    size_t row_count;
    /**
     * Receiver WGS84 geodetic position.
     */
    struct SidereonGeodetic receiver;
    /**
     * Receiver-clock systems as SidereonGnssSystem values.
     */
    const uint32_t *clock_systems;
    /**
     * Number of receiver-clock systems.
     */
    size_t clock_system_count;
} SidereonAraimGeometry;

/**
 * Per-satellite ARAIM integrity and accuracy model without an identity.
 */
typedef struct SidereonAraimSatelliteIsmModel {
    /**
     * Integrity one-sigma SIS range error, meters.
     */
    double sigma_ura_m;
    /**
     * Accuracy and continuity one-sigma SIS range error, meters.
     */
    double sigma_ure_m;
    /**
     * Whether effective_sigma_int_m overrides the derived integrity sigma.
     */
    bool has_effective_sigma_int_m;
    /**
     * Effective integrity one-sigma range error after local terms, meters.
     */
    double effective_sigma_int_m;
    /**
     * Whether effective_sigma_acc_m overrides the derived accuracy sigma.
     */
    bool has_effective_sigma_acc_m;
    /**
     * Effective accuracy one-sigma range error after local terms, meters.
     */
    double effective_sigma_acc_m;
    /**
     * Nominal SIS bias bound, meters.
     */
    double b_nom_m;
    /**
     * Prior probability for a satellite fault.
     */
    double p_sat;
} SidereonAraimSatelliteIsmModel;

/**
 * Per-constellation ARAIM ISM default.
 */
typedef struct SidereonAraimConstellationIsm {
    /**
     * GNSS system as SidereonGnssSystem.
     */
    uint32_t system;
    /**
     * Prior probability for a constellation-wide fault.
     */
    double p_const;
    /**
     * Default satellite model for this constellation.
     */
    struct SidereonAraimSatelliteIsmModel default_sat;
} SidereonAraimConstellationIsm;

/**
 * Per-satellite ARAIM ISM override.
 */
typedef struct SidereonAraimSatelliteIsm {
    /**
     * Null-terminated satellite token.
     */
    const char *sat_id;
    /**
     * Integrity one-sigma SIS range error, meters.
     */
    double sigma_ura_m;
    /**
     * Accuracy and continuity one-sigma SIS range error, meters.
     */
    double sigma_ure_m;
    /**
     * Whether effective_sigma_int_m overrides the derived integrity sigma.
     */
    bool has_effective_sigma_int_m;
    /**
     * Effective integrity one-sigma range error after local terms, meters.
     */
    double effective_sigma_int_m;
    /**
     * Whether effective_sigma_acc_m overrides the derived accuracy sigma.
     */
    bool has_effective_sigma_acc_m;
    /**
     * Effective accuracy one-sigma range error after local terms, meters.
     */
    double effective_sigma_acc_m;
    /**
     * Nominal SIS bias bound, meters.
     */
    double b_nom_m;
    /**
     * Prior probability for a satellite fault.
     */
    double p_sat;
} SidereonAraimSatelliteIsm;

/**
 * ARAIM integrity support message input. Arrays are caller-owned.
 */
typedef struct SidereonAraimIsm {
    /**
     * Per-constellation defaults.
     */
    const struct SidereonAraimConstellationIsm *constellations;
    /**
     * Number of constellation rows.
     */
    size_t constellation_count;
    /**
     * Per-satellite overrides.
     */
    const struct SidereonAraimSatelliteIsm *satellites;
    /**
     * Number of satellite override rows.
     */
    size_t satellite_count;
} SidereonAraimIsm;

/**
 * Integrity and continuity risk allocation for one ARAIM solve.
 */
typedef struct SidereonAraimIntegrityAllocation {
    /**
     * Total probability of hazardous misleading information.
     */
    double phmi_total;
    /**
     * Vertical PHMI allocation.
     */
    double phmi_vert;
    /**
     * Horizontal PHMI allocation.
     */
    double phmi_hor;
    /**
     * Vertical false-alert allocation.
     */
    double pfa_vert;
    /**
     * Horizontal false-alert allocation.
     */
    double pfa_hor;
    /**
     * Maximum acceptable unmonitored fault probability mass.
     */
    double p_threshold_unmonitored;
    /**
     * Fault-prior threshold used for the effective monitor threshold.
     */
    double p_emt;
    /**
     * Maximum enumerated satellite-fault order. Zero keeps only fault-free.
     */
    size_t max_fault_order;
} SidereonAraimIntegrityAllocation;

/**
 * Fixed-size null-terminated satellite token storage. The token is valid up
 * to the first null byte; for example G08. Values returned by Sidereon are
 * always null-terminated.
 */
typedef struct SidereonSatelliteToken {
    /**
     * Null-terminated token bytes.
     */
    char bytes[17];
} SidereonSatelliteToken;

/**
 * One ARAIM fault-mode row. Sigma, bias, and threshold arrays are local
 * `[east, north, up]` meters.
 */
typedef struct SidereonAraimFaultMode {
    /**
     * Number of excluded satellites for this mode.
     */
    size_t excluded_count;
    /**
     * Whether excluded_constellation carries a GNSS system.
     */
    bool has_excluded_constellation;
    /**
     * Excluded constellation as SidereonGnssSystem when present.
     */
    uint32_t excluded_constellation;
    /**
     * Fault prior probability for this mode.
     */
    double prior;
    /**
     * Integrity sigma in local ENU, meters.
     */
    double sigma_int_enu_m[3];
    /**
     * Nominal bias bound in local ENU, meters.
     */
    double bias_enu_m[3];
    /**
     * Separation monitor threshold in local ENU, meters.
     */
    double threshold_enu_m[3];
    /**
     * True when the subset geometry is full rank.
     */
    bool monitorable;
} SidereonAraimFaultMode;

/**
 * ARAIM protection-level summary. HPL, VPL, EMT, and accuracy sigma fields are
 * meters.
 */
typedef struct SidereonAraimSummary {
    /**
     * Horizontal protection level, meters.
     */
    double hpl_m;
    /**
     * Vertical protection level, meters.
     */
    double vpl_m;
    /**
     * All-in-view horizontal accuracy sigma, meters.
     */
    double sigma_acc_h_m;
    /**
     * All-in-view vertical accuracy sigma, meters.
     */
    double sigma_acc_v_m;
    /**
     * Effective monitor threshold, meters.
     */
    double emt_m;
    /**
     * Unenumerated plus unmonitorable fault probability mass.
     */
    double p_unmonitored;
    /**
     * True when the solve met the allocation and all roots converged.
     */
    bool availability;
    /**
     * Number of fault-mode rows available.
     */
    size_t fault_mode_count;
} SidereonAraimSummary;

/**
 * Inputs to the NRLMSISE-00 neutral-atmosphere evaluation.
 *
 * When `has_lst` is false the core derives local apparent solar time from `sec`
 * and `lon_deg`; when true, `lst` (hours) is used verbatim. When `has_ap_array`
 * is false the scalar `ap` drives the daily magnetic forcing (switch 9 off);
 * when true, `ap_array` supplies the Ap history for Ap-history mode. Source the
 * quiet-Sun defaults for `f107`, `f107a`, and `ap` from
 * sidereon_atmosphere_input_default.
 */
typedef struct SidereonAtmosphereInput {
    /**
     * Calendar year.
     */
    int32_t year;
    /**
     * Day of year, 1-366.
     */
    int32_t doy;
    /**
     * Seconds into the UTC day.
     */
    double sec;
    /**
     * Geodetic altitude, kilometers (valid in [0, 1000]).
     */
    double alt_km;
    /**
     * Geodetic latitude, degrees.
     */
    double lat_deg;
    /**
     * Geodetic longitude, degrees.
     */
    double lon_deg;
    /**
     * Whether `lst` carries a caller-supplied local solar time. When false the
     * core derives it from `sec` and `lon_deg`.
     */
    bool has_lst;
    /**
     * Local apparent solar time, hours. Used only when has_lst is true.
     */
    double lst;
    /**
     * Daily F10.7 solar flux.
     */
    double f107;
    /**
     * 81-day average F10.7 solar flux.
     */
    double f107a;
    /**
     * Daily magnetic index Ap. Used when has_ap_array is false.
     */
    double ap;
    /**
     * Whether `ap_array` carries an Ap history (selects Ap-history mode).
     */
    bool has_ap_array;
    /**
     * Ap history, used only when has_ap_array is true.
     */
    double ap_array[SIDEREON_ATMOSPHERE_AP_ARRAY_LEN];
} SidereonAtmosphereInput;

/**
 * NRLMSISE-00 output.
 */
typedef struct SidereonAtmosphereOutput {
    /**
     * Total mass density, kilograms per cubic meter.
     */
    double density_kg_m3;
    /**
     * Temperature at the requested altitude, kelvin.
     */
    double temperature_k;
} SidereonAtmosphereOutput;

typedef struct SidereonBiasEpoch {
    int32_t year;
    uint16_t day_of_year;
    uint32_t second_of_day;
} SidereonBiasEpoch;

typedef struct SidereonBiasRecord {
    enum SidereonBiasKind kind;
    enum SidereonBiasTargetKind target_kind;
    enum SidereonGnssSystem system;
    bool has_sat_id;
    struct SidereonSatelliteToken sat_id;
    char station[BIAS_TEXT_C_BYTES];
    char svn[BIAS_TEXT_C_BYTES];
    char obs1[BIAS_OBS_C_BYTES];
    bool has_obs2;
    char obs2[BIAS_OBS_C_BYTES];
    bool has_valid_from;
    struct SidereonBiasEpoch valid_from;
    bool has_valid_until;
    struct SidereonBiasEpoch valid_until;
    double value;
    bool has_sigma;
    double sigma;
    bool has_slope;
    double slope;
    bool has_slope_sigma;
    double slope_sigma;
    bool is_phase;
} SidereonBiasRecord;

/**
 * Scalar outcome of an integer least-squares search. The best integer vector
 * itself is written to the caller's out_fixed buffer (n entries, parallel to the
 * input float_cycles); these are the accompanying scores and the ratio-test
 * verdict. Mirrors the scalar fields of sidereon_core::ils::IlsResult; the
 * symmetrized covariance / inverse it also carries are diagnostic and not
 * surfaced here.
 */
typedef struct SidereonIlsResult {
    /**
     * Whether the ratio test passes at the requested threshold (the fix is
     * accepted).
     */
    bool fixed_status;
    /**
     * Runner-up / best score ratio. Saturates to DBL_MAX when the best score is
     * exactly zero with a positive runner-up; 0 when there is no runner-up.
     */
    double ratio;
    /**
     * Best (lowest) quadratic score.
     */
    double best_score;
    /**
     * True when second_best_score carries a value (a runner-up lattice point
     * existed).
     */
    bool second_best_present;
    /**
     * Runner-up score, valid only when second_best_present is true.
     */
    double second_best_score;
    /**
     * Number of lattice points evaluated.
     */
    size_t candidates_evaluated;
} SidereonIlsResult;

/**
 * One comparison epoch, mirroring
 * sidereon_core::broadcast_comparison::EpochInputs. The precise/plus/minus
 * fields are split Julian dates (whole + fraction) at which the precise SP3 is
 * evaluated for the central, look-ahead, and look-back samples.
 */
typedef struct SidereonCompareEpoch {
    /**
     * Broadcast evaluation epoch in J2000 seconds.
     */
    double broadcast_t_j2000_s;
    /**
     * Central precise epoch, whole Julian day.
     */
    double precise_jd_whole;
    /**
     * Central precise epoch, Julian-day fraction.
     */
    double precise_jd_fraction;
    /**
     * Look-ahead precise epoch, whole Julian day.
     */
    double precise_plus_jd_whole;
    /**
     * Look-ahead precise epoch, Julian-day fraction.
     */
    double precise_plus_jd_fraction;
    /**
     * Look-back precise epoch, whole Julian day.
     */
    double precise_minus_jd_whole;
    /**
     * Look-back precise epoch, Julian-day fraction.
     */
    double precise_minus_jd_fraction;
} SidereonCompareEpoch;

/**
 * A regularly sampled comparison window, mirroring
 * sidereon_core::broadcast_comparison::CompareWindow. The broadcast product is
 * queried on the continuous J2000-second axis; the precise product is queried by
 * split Julian date advanced from precise_start in lockstep.
 */
typedef struct SidereonCompareWindow {
    /**
     * Inclusive broadcast query window start, continuous seconds since J2000.
     */
    double broadcast_window_start_j2000_s;
    /**
     * Inclusive broadcast query window end, continuous seconds since J2000.
     */
    double broadcast_window_end_j2000_s;
    /**
     * Precise query for the window start, whole Julian day.
     */
    double precise_start_jd_whole;
    /**
     * Precise query for the window start, Julian-day fraction.
     */
    double precise_start_jd_fraction;
    /**
     * Sampling step between consecutive epochs, seconds.
     */
    double step_s;
    /**
     * Velocity finite-difference half step, seconds.
     */
    double velocity_half_s;
} SidereonCompareWindow;

/**
 * SISRE comparison statistics, mirroring
 * sidereon_core::broadcast_comparison::CompareStats. Each optional metric is NaN
 * when undefined for the sample.
 */
typedef struct SidereonCompareStats {
    /**
     * Number of compared samples.
     */
    size_t count;
    /**
     * 3D orbit error RMS, meters (NaN if undefined).
     */
    double orbit_3d_rms_m;
    /**
     * 3D orbit error max, meters.
     */
    double orbit_3d_max_m;
    /**
     * Radial error RMS, meters.
     */
    double radial_rms_m;
    /**
     * Radial error max, meters.
     */
    double radial_max_m;
    /**
     * Along-track error RMS, meters.
     */
    double along_rms_m;
    /**
     * Along-track error max, meters.
     */
    double along_max_m;
    /**
     * Cross-track error RMS, meters.
     */
    double cross_rms_m;
    /**
     * Cross-track error max, meters.
     */
    double cross_max_m;
    /**
     * Clock error RMS, meters.
     */
    double clock_rms_m;
    /**
     * Clock error max, meters.
     */
    double clock_max_m;
    /**
     * Datum-removed clock error RMS, meters.
     */
    double clock_datum_removed_rms_m;
    /**
     * Datum-removed clock error max, meters.
     */
    double clock_datum_removed_max_m;
} SidereonCompareStats;

