    size_t vmf_sample_count;
    /**
     * VMF1 site-wise a-coefficient series, ascending in mjd.
     */
    struct SidereonPppVmfSiteSample vmf_samples[SIDEREON_PPP_VMF_SITE_MAX_SAMPLES];
