enum SidereonStatus sidereon_error_metrics_from_enu_covariance_m2(const double *covariance_enu_m2,
                                                                  struct SidereonPositionErrorMetrics *out_metrics,
                                                                  enum SidereonErrorMetricsErrorKind *out_error);

