enum SidereonStatus sidereon_glonass_g1_frequency_hz(int8_t channel, double *out);

/**
 * Write seconds of week for a calendar date and time.
 *
 * Safety: out_sow_s points to a double.
 */
enum SidereonStatus sidereon_gnss_seconds_of_week_from_calendar(int64_t year,
                                                                int64_t month,
                                                                int64_t day,
                                                                int64_t hour,
                                                                int64_t minute,
                                                                int64_t second,
                                                                double *out_sow_s);

/**
 * Copy the core conventional GNSS system label into out.
 */
enum SidereonStatus sidereon_gnss_system_label(uint32_t system,
                                               uint8_t *out,
                                               size_t len,
                                               size_t *out_written,
                                               size_t *out_required);

/**
 * Split continuous seconds since a system week epoch into week and seconds of
 * week.
 *
 * Safety: out_week and out_sow_s point to doubles.
 */
enum SidereonStatus sidereon_gnss_week_and_seconds_of_week(double continuous_seconds,
                                                           double *out_week,
                                                           double *out_sow_s);

