enum SidereonStatus sidereon_spp_solution_system_tdops(const struct SidereonSppSolution *sol,
                                                       struct SidereonSppSystemTdop *out,
                                                       size_t len,
                                                       size_t *out_written,
                                                       size_t *out_required);

