enum SidereonStatus sidereon_static_position_solution_position_covariance_enu_m2(const struct SidereonStaticPositionSolution *solution,
                                                                                 double *out_m2,
                                                                                 size_t len);

/**
 * Copy rejected satellites for one input epoch. Output uses the
 * variable-length contract.
 *
 * Safety: solution must be a live handle; out must point to len entries or be
 * NULL when len is 0; out_written and out_required must point to size_t.
 */
enum SidereonStatus sidereon_static_position_solution_rejected_sats(const struct SidereonStaticPositionSolution *solution,
                                                                    size_t epoch_index,
                                                                    struct SidereonSppRejectedSat *out,
                                                                    size_t len,
                                                                    size_t *out_written,
                                                                    size_t *out_required);

/**
 * Copy post-fit residual rows. Output uses the variable-length contract.
 *
 * Safety: solution must be a live handle; out must point to len entries or be
 * NULL when len is 0; out_written and out_required must point to size_t.
 */
enum SidereonStatus sidereon_static_position_solution_residuals(const struct SidereonStaticPositionSolution *solution,
                                                                struct SidereonStaticPositionResidual *out,
                                                                size_t len,
                                                                size_t *out_written,
                                                                size_t *out_required);

/**
 * Copy leave-one-satellite-out diagnostics grouped across epochs. Output uses
 * the variable-length contract.
 *
 * Safety: solution must be a live handle; out must point to len entries or be
 * NULL when len is 0; out_written and out_required must point to size_t.
 */
enum SidereonStatus sidereon_static_position_solution_satellite_batch_influence(const struct SidereonStaticPositionSolution *solution,
                                                                                struct SidereonStaticPositionSatelliteBatchInfluence *out,
                                                                                size_t len,
                                                                                size_t *out_written,
                                                                                size_t *out_required);

/**
 * Copy leave-one-satellite-out diagnostics by epoch. Output uses the
 * variable-length contract.
 *
 * Safety: solution must be a live handle; out must point to len entries or be
 * NULL when len is 0; out_written and out_required must point to size_t.
 */
enum SidereonStatus sidereon_static_position_solution_satellite_influence(const struct SidereonStaticPositionSolution *solution,
                                                                          struct SidereonStaticPositionSatelliteInfluence *out,
                                                                          size_t len,
                                                                          size_t *out_written,
                                                                          size_t *out_required);

/**
 * Copy the full static state covariance in row-major order. Output uses the
 * variable-length contract documented in the header.
 *
 * Safety: solution must be a live handle; out must point to len doubles or be
 * NULL when len is 0; out_written and out_required must point to size_t.
 */
enum SidereonStatus sidereon_static_position_solution_state_covariance_m2(const struct SidereonStaticPositionSolution *solution,
                                                                          double *out,
                                                                          size_t len,
                                                                          size_t *out_written,
                                                                          size_t *out_required);

/**
 * Return a static, null-terminated, human-readable name for a status code.
 *
 * The pointer refers to static storage and is valid for the lifetime of the
 * program; do not free it. Unlike sidereon_last_error_message, which gives the
 * specific reason for the most recent failure, this maps the status enum itself
 * to a fixed string and never depends on thread-local state. An unrecognized
 * value yields "unknown status".
 */
const char *sidereon_status_message(enum SidereonStatus status);

/**
 * Sub-observer point (planetary central meridian) on a rotating body, from the
 * observer position relative to the body center (inertial frame) and the body's
 * IAU orientation (degrees). Delegates to
 * sidereon_core::astro::observation::sub_observer_point.
 *
 * Safety: observer_from_body points to 3 doubles; out points to a
 * SidereonSurfacePoint.
 */
enum SidereonStatus sidereon_sub_observer_point(const double *observer_from_body,
                                                double pole_ra_deg,
                                                double pole_dec_deg,
                                                double prime_meridian_deg,
                                                struct SidereonSurfacePoint *out);

/**
 * Sub-solar point: the geographic point where the Sun is at the zenith.
 * `sun_ecef` is the geocentric Sun position in an Earth-fixed frame (only its
 * direction matters). Delegates to
 * sidereon_core::astro::observation::sub_solar_point.
 *
 * Safety: sun_ecef points to 3 doubles; out points to a SidereonSurfacePoint.
 */
enum SidereonStatus sidereon_sub_solar_point(const double *sun_ecef,
                                             struct SidereonSurfacePoint *out);

/**
 * Sun aspect angle in degrees between satellite and Sun directions. Delegates
 * to sidereon_core::astro::angles::sun_angle. Position vectors are in km.
 *
 * Safety: sat_pos_km and sun_pos_km must point to 3 doubles; out to a double.
 */
enum SidereonStatus sidereon_sun_angle_deg(const double *sat_pos_km,
                                           const double *sun_pos_km,
                                           double *out);

/**
 * Topocentric azimuth/elevation/range of the Sun from a ground site at an
 * instant, written to *out. Delegates to the core `sun_az_el`.
 *
 * Safety: station must point to a SidereonGeodeticStation; out must point to a
 * SidereonBodyAzEl.
 */
enum SidereonStatus sidereon_sun_az_el(const struct SidereonGeodeticStation *station,
                                       int64_t time_unix_us,
                                       struct SidereonBodyAzEl *out);

/**
 * Sun elevation in degrees at the satellite. Delegates to
 * sidereon_core::astro::angles::sun_elevation.
 *
 * Safety: sat_pos_km and sun_pos_km must point to 3 doubles; out to a double.
 */
enum SidereonStatus sidereon_sun_elevation_deg(const double *sat_pos_km,
                                               const double *sun_pos_km,
                                               double *out);

/**
 * Analytic Sun and Moon positions in Earth-fixed ECEF, metres, for one
 * unix-microsecond UTC epoch. Delegates to
 * sidereon_core::astro::bodies::sun_moon_ecef.
 *
 * Safety: out_sun_m and out_moon_m must each point to 3 doubles.
 */
enum SidereonStatus sidereon_sun_moon_ecef(int64_t epoch_unix_us,
                                           double *out_sun_m,
                                           double *out_moon_m);

/**
 * Analytic Sun and Moon positions in Earth-fixed ECEF, metres, for a batch of
 * unix-microsecond UTC epochs. Delegates to
 * sidereon_core::astro::bodies::sun_moon_ecef.
 *
 * Safety: epochs_unix_us must point to count int64_t values; out_sun_m and
 * out_moon_m must each point to at least 3 * count doubles.
 */
enum SidereonStatus sidereon_sun_moon_ecef_batch(const int64_t *epochs_unix_us,
                                                 size_t count,
                                                 double *out_sun_m,
                                                 size_t sun_len,
                                                 double *out_moon_m,
                                                 size_t moon_len);

/**
 * Geocentric Sun and Moon positions in meters (ECI, mean equator/equinox of
 * date) at a TT epoch expressed in Julian centuries since J2000. Delegates to
 * sidereon_core::astro::bodies::sun_moon_eci.
 *
 * Safety: out_sun_m and out_moon_m must each point to 3 doubles.
 */
enum SidereonStatus sidereon_sun_moon_eci(double tt_julian_centuries,
                                          double *out_sun_m,
                                          double *out_moon_m);

/**
 * Analytic Sun and Moon positions in geocentric ECI, metres, for a batch of
 * unix-microsecond UTC epochs. Delegates to
 * sidereon_core::astro::bodies::sun_moon_eci_at.
 *
 * Safety: epochs_unix_us must point to count int64_t values; out_sun_m and
 * out_moon_m must each point to at least 3 * count doubles.
 */
enum SidereonStatus sidereon_sun_moon_eci_batch(const int64_t *epochs_unix_us,
                                                size_t count,
                                                double *out_sun_m,
                                                size_t sun_len,
                                                double *out_moon_m,
                                                size_t moon_len);

/**
 * TAI - UTC (the IERS / Bulletin C leap-second count) at a UTC Julian date,
 * written to *out. 37 s from 2017-01-01. Delegates to the core
 * `tai_utc_offset_s`. For the GNSS "GPS - UTC" quantity use
 * sidereon_gps_utc_offset_s instead.
 *
 * Safety: out must point to a double.
 */
enum SidereonStatus sidereon_tai_utc_offset_s(double jd_utc, double *out);

/**
 * Compute Pc for an already-refined TCA candidate. Delegates to
 * sidereon_core::astro::tca::tca_collision_probability.
 *
 * Safety: candidate points to a SidereonTcaCandidate; options to a
 * SidereonTcaPcOptions; out to a SidereonTcaConjunction.
 */
enum SidereonStatus sidereon_tca_collision_probability(const struct SidereonTcaCandidate *candidate,
                                                       const struct SidereonTcaPcOptions *options,
                                                       struct SidereonTcaConjunction *out);

/**
 * Fill *out_options with the engine default TCA finder options.
 *
 * Safety: out_options must point to writable storage.
 */
enum SidereonStatus sidereon_tca_finder_options_init(struct SidereonTcaFinderOptions *out_options);

/**
 * Release a TDM handle. Passing NULL is a no-op.
 *
 * Safety: tdm must be NULL or a live handle from sidereon_tdm_parse_kvn.
 */
void sidereon_tdm_free(struct SidereonTdm *tdm);

/**
 * Parse a CCSDS TDM in KVN form. On success writes a newly owned handle to
 * *out_tdm. Release it with sidereon_tdm_free.
 *
 * Safety: data must point to len readable bytes; out_tdm must point to
 * storage for a SidereonTdm*.
 */
enum SidereonStatus sidereon_tdm_parse_kvn(const uint8_t *data,
                                           size_t len,
                                           struct SidereonTdm **out_tdm);

/**
 * Copy parsed TDM participant entries across all segments.
 *
 * Safety: tdm must be live; output pointers follow the variable-length output
 * contract.
 */
enum SidereonStatus sidereon_tdm_participants(const struct SidereonTdm *tdm,
                                              struct SidereonTdmParticipant *out,
                                              size_t len,
                                              size_t *out_written,
                                              size_t *out_required);

/**
 * Copy parsed TDM path entries across all segments.
 *
 * Safety: tdm must be live; output pointers follow the variable-length output
 * contract.
 */
enum SidereonStatus sidereon_tdm_paths(const struct SidereonTdm *tdm,
                                       struct SidereonTdmPath *out,
                                       size_t len,
                                       size_t *out_written,
                                       size_t *out_required);

/**
 * Write the total number of TDM data records to *out_count.
 *
 * Safety: tdm must be live; out_count must point to size_t storage.
 */
enum SidereonStatus sidereon_tdm_record_count(const struct SidereonTdm *tdm, size_t *out_count);

/**
 * Copy flattened TDM data records across all segments.
 *
 * Safety: tdm must be live; output pointers follow the variable-length output
 * contract.
 */
enum SidereonStatus sidereon_tdm_records(const struct SidereonTdm *tdm,
                                         struct SidereonTdmDataRecord *out,
                                         size_t len,
                                         size_t *out_written,
                                         size_t *out_required);

/**
 * Write the number of TDM segments to *out_count.
 *
 * Safety: tdm must be live; out_count must point to size_t storage.
 */
enum SidereonStatus sidereon_tdm_segment_count(const struct SidereonTdm *tdm, size_t *out_count);

/**
 * Copy TDM segment summaries.
 *
 * Safety: tdm must be live; out must point to len writable entries or be NULL
 * when len is 0; out_written and out_required must point to size_t storage.
 */
enum SidereonStatus sidereon_tdm_segments(const struct SidereonTdm *tdm,
                                          struct SidereonTdmSegmentSummary *out,
                                          size_t len,
                                          size_t *out_written,
                                          size_t *out_required);

/**
 * Serialize a TDM to KVN text. The output is not null-terminated.
 *
 * Safety: tdm must be a live handle; out must point to len writable bytes or
 * be NULL when len is 0; out_written and out_required must point to size_t
 * storage.
 */
enum SidereonStatus sidereon_tdm_to_kvn(const struct SidereonTdm *tdm,
                                        uint8_t *out,
                                        size_t len,
                                        size_t *out_written,
                                        size_t *out_required);

/**
 * Latitude (degrees) of the day-night terminator at a query longitude, given
 * the sub-solar point. Delegates to
 * sidereon_core::astro::observation::terminator_latitude_deg.
 *
 * Safety: out_latitude_deg points to a double.
 */
enum SidereonStatus sidereon_terminator_latitude_deg(double sub_solar_latitude_deg,
                                                     double sub_solar_longitude_deg,
                                                     double longitude_deg,
                                                     double *out_latitude_deg);

/**
 * Return an FNV-1a checksum for terrain store bytes.
 *
 * Safety: bytes must point to len readable bytes; out_checksum64 must point to
 * a uint64_t.
 */
enum SidereonStatus sidereon_terrain_store_checksum64(const uint8_t *bytes,
                                                      size_t len,
                                                      uint64_t *out_checksum64);

/**
 * Copy a time-scale abbreviation such as "GPST". Delegates to
 * sidereon_core::astro::time::TimeScale::abbrev.
 *
 * Safety: out must point to out_len writable bytes or be NULL when out_len is
 * zero; out_written and out_required must point to size_t values.
 */
enum SidereonStatus sidereon_time_scale_abbrev(uint32_t scale,
                                               uint8_t *out,
                                               size_t out_len,
                                               size_t *out_written,
                                               size_t *out_required);

/**
 * Write the leap-aware inter-system time-scale offset to_reading - from_reading
 * (seconds) at the UTC instant utc_jd to *out_offset_s. utc_jd is the UTC
 * Julian date, used only to resolve the leap-second count when from or to is
 * UTC-based (UTC/GLONASST); it is ignored for purely atomic pairs. Fails with
 * SIDEREON_STATUS_INVALID_ARGUMENT for TDB or when a UTC-based scale is named
 * with a non-finite utc_jd.
 *
 * Safety: out_offset_s must point to a double.
 */
enum SidereonStatus sidereon_timescale_offset_at_s(uint32_t from,
                                                   uint32_t to,
                                                   double utc_jd,
                                                   double *out_offset_s);

/**
 * Write the fixed inter-system time-scale offset to_reading - from_reading
 * (seconds) to *out_offset_s: the value that, added to a from-scale reading,
 * yields the to-scale reading of the same instant. Both scales are
 * SidereonTimeScale values. Fails with SIDEREON_STATUS_INVALID_ARGUMENT if
 * either scale is UTC-based (UTC/GLONASST), whose offset is epoch-dependent (use
 * sidereon_timescale_offset_at_s), or for TDB.
 *
 * Safety: out_offset_s must point to a double.
 */
enum SidereonStatus sidereon_timescale_offset_s(uint32_t from, uint32_t to, double *out_offset_s);

/**
 * Resolve the split-Julian-date time scales for a UTC calendar instant.
 * Delegates to sidereon_core::astro::time::scales::TimeScales::from_utc.
 *
 * Safety: out must point to a SidereonTimeScales.
 */
enum SidereonStatus sidereon_timescales_from_utc(int32_t year,
                                                 int32_t month,
                                                 int32_t day,
                                                 int32_t hour,
                                                 int32_t minute,
                                                 double second,
                                                 struct SidereonTimeScales *out);

/**
 * Compute topocentric look angles for a fleet of TLEs over a shared epoch
 * grid. When parallel is true the engine's rayon batch path is used. On
 * success writes a newly owned batch handle to *out_batch. Release it with
 * sidereon_tle_batch_look_angles_free.
 *
 * Safety: tles must point to tle_count line pairs; station must point to a
 * SidereonGroundStation; epochs_unix_us must point to epoch_count int64_t
 * values; out_batch must point to handle storage.
 */
enum SidereonStatus sidereon_tle_batch_look_angles(const struct SidereonTlePair *tles,
                                                   size_t tle_count,
                                                   const struct SidereonGroundStation *station,
                                                   const int64_t *epochs_unix_us,
                                                   size_t epoch_count,
                                                   uint32_t opsmode,
                                                   bool parallel,
                                                   struct SidereonTleBatchLookAngles **out_batch);

/**
 * Release a batched look-angle handle. Null is a no-op. A non-null handle must
 * come from sidereon_tle_batch_look_angles and must be freed exactly once with
 * this function.
 *
 * Safety: batch must be NULL or a live handle from
 * sidereon_tle_batch_look_angles. Passing a handle after it has already been
 * freed is invalid.
 */
void sidereon_tle_batch_look_angles_free(struct SidereonTleBatchLookAngles *batch);

/**
 * Copy the shape of a batched look-angle result as satellite_count and
 * epoch_count.
 *
 * Safety: batch must be a live handle; out_satellite_count and out_epoch_count
 * must point to size_t values.
 */
enum SidereonStatus sidereon_tle_batch_look_angles_shape(const struct SidereonTleBatchLookAngles *batch,
                                                         size_t *out_satellite_count,
                                                         size_t *out_epoch_count);

/**
 * Copy flattened satellite-major look-angle rows from a batched result. Uses
 * the variable-length output contract documented at the top of the header.
 *
 * Safety: batch must be a live handle; out must point to at least len writable
 * entries or be NULL when len is 0; out_written and out_required must point to
 * size_t values.
 */
enum SidereonStatus sidereon_tle_batch_look_angles_values(const struct SidereonTleBatchLookAngles *batch,
                                                          struct SidereonLookAngle *out,
                                                          size_t len,
                                                          size_t *out_written,
                                                          size_t *out_required);

/**
 * Release a batched propagation handle. Null is a no-op. A non-null handle
 * must come from sidereon_propagate_tle_batch and must be freed exactly once
 * with this function.
 *
 * Safety: batch must be NULL or a live handle from
 * sidereon_propagate_tle_batch. Passing a handle after it has already been
 * freed is invalid.
 */
void sidereon_tle_batch_propagation_free(struct SidereonTleBatchPropagation *batch);

/**
 * Copy the shape of a batched propagation as satellite_count and epoch_count.
 *
 * Safety: batch must be a live handle; out_satellite_count and out_epoch_count
 * must point to size_t values.
 */
enum SidereonStatus sidereon_tle_batch_propagation_shape(const struct SidereonTleBatchPropagation *batch,
                                                         size_t *out_satellite_count,
                                                         size_t *out_epoch_count);

/**
 * Copy flattened satellite-major TEME states from a batched propagation. Uses
 * the variable-length output contract documented at the top of the header.
 *
 * Safety: batch must be a live handle; out must point to at least len writable
 * entries or be NULL when len is 0; out_written and out_required must point to
 * size_t values.
 */
enum SidereonStatus sidereon_tle_batch_propagation_states(const struct SidereonTleBatchPropagation *batch,
                                                          struct SidereonTemeState *out,
                                                          size_t len,
                                                          size_t *out_written,
                                                          size_t *out_required);

/**
 * Copy advisory TLE checksum warnings. Uses the variable-length output
 * contract documented at the top of the header.
 *
 * Safety: tle must be a live handle; out must point to at least len writable
 * entries or be NULL when len is 0; out_written and out_required must point to
 * size_t values.
 */
enum SidereonStatus sidereon_tle_checksum_warnings(const struct SidereonTle *tle,
                                                   struct SidereonTleChecksumWarning *out,
                                                   size_t len,
                                                   size_t *out_written,
                                                   size_t *out_required);

/**
 * Write the number of successfully parsed satellites in a TLE file to
 * *out_count.
 *
 * Safety: file must be a live handle; out_count must point to a size_t.
 */
enum SidereonStatus sidereon_tle_file_count(const struct SidereonTleFile *file, size_t *out_count);

/**
 * Release a parsed TLE file handle. Null is a no-op. A non-null handle must
 * come from sidereon_parse_tle_file and must be freed exactly once with this
 * function. TLE handles previously obtained with sidereon_tle_file_satellite
 * are independent and are unaffected by freeing the file.
 *
 * Safety: file must be NULL or a live handle from sidereon_parse_tle_file.
 * Passing a handle after it has already been freed is invalid.
 */
void sidereon_tle_file_free(struct SidereonTleFile *file);

/**
 * Copy the name line for the record at index into buf as a null-terminated C
 * string. Writes the total number of bytes required (including the
 * terminator) to *out_required. Pass buf NULL with len 0 to query the size;
 * the name is empty for a bare 2-line set, for which out_required is 1. If len
 * is nonzero but smaller than out_required, returns InvalidArgument and leaves
 * buf null-terminated (empty) when len is positive.
 *
 * Safety: file must be a live handle; buf must point to at least len writable
 * bytes or be NULL when len is 0; out_required must point to a size_t.
 */
enum SidereonStatus sidereon_tle_file_name(const struct SidereonTleFile *file,
                                           size_t index,
                                           char *buf,
                                           size_t len,
                                           size_t *out_required);

/**
 * Write a newly owned, independent copy of the TLE handle for the record at
 * index to *out_tle. The returned handle can be used with any sidereon_tle_*
 * entry point (propagation, look-angles, metadata) and outlives the file; it
 * must be released with sidereon_tle_free.
 *
 * Safety: file must be a live handle; out_tle must point to storage for a
 * SidereonTle*.
 */
enum SidereonStatus sidereon_tle_file_satellite(const struct SidereonTleFile *file,
                                                size_t index,
                                                struct SidereonTle **out_tle);

/**
 * Write the number of records that were found but skipped because their element
 * set failed SGP4 initialization to *out_skipped. An empty file
 * (count == 0, skipped == 0) is thus distinguishable from a fully corrupt one
 * (count == 0, skipped > 0).
 *
 * Safety: file must be a live handle; out_skipped must point to a size_t.
 */
enum SidereonStatus sidereon_tle_file_skipped(const struct SidereonTleFile *file,
                                              size_t *out_skipped);

/**
 * Find dense passes over a ground station within [start_unix_us, end_unix_us).
 * options may be NULL for defaults. On success writes a newly owned pass-list
 * handle to *out_passes. Release it with sidereon_pass_list_free.
 *
 * Safety: tle must be a live handle; station must point to a
 * SidereonGroundStation; out_passes must point to handle storage.
 */
enum SidereonStatus sidereon_tle_find_passes(const struct SidereonTle *tle,
                                             const struct SidereonGroundStation *station,
                                             int64_t start_unix_us,
                                             int64_t end_unix_us,
                                             const struct SidereonPassFinderOptions *options,
                                             struct SidereonPassList **out_passes);

/**
 * Release a TLE handle. Null is a no-op. A non-null handle must come from
 * sidereon_tle_load and must be freed exactly once with this function.
 *
 * Safety: tle must be NULL or a live handle from sidereon_tle_load. Passing a
 * handle after it has already been freed is invalid.
 */
void sidereon_tle_free(struct SidereonTle *tle);

/**
 * Compute the per-epoch sub-satellite (ground-track) geodetic points for a TLE
 * over UTC unix-microsecond epochs. On success writes a newly owned arc handle
 * to *out_track. Release it with sidereon_ground_track_free.
 *
 * Safety: tle must be a live handle; epochs_unix_us must point to epoch_count
 * int64_t values; out_track must point to handle storage.
 */
enum SidereonStatus sidereon_tle_ground_track(const struct SidereonTle *tle,
                                              const int64_t *epochs_unix_us,
                                              size_t epoch_count,
                                              struct SidereonGroundTrack **out_track);

/**
 * Parse a TLE line pair and initialize an SGP4 satellite. opsmode is one of
 * SidereonTleOpsMode_* encoded as uint32_t. On success writes a newly owned
 * handle to *out_tle. Release it with sidereon_tle_free.
 *
 * Safety: line1 and line2 must be null-terminated within 128 bytes; out_tle
 * must point to storage for a SidereonTle*.
 */
enum SidereonStatus sidereon_tle_load(const char *line1,
                                      const char *line2,
                                      uint32_t opsmode,
                                      struct SidereonTle **out_tle);

/**
 * Compute topocentric look angles from a TLE over UTC unix-microsecond epochs.
 * On success writes a newly owned handle to *out_look_angles. Release it with
 * sidereon_look_angles_free.
 *
 * Safety: tle must be a live handle; station must point to a
 * SidereonGroundStation; epochs_unix_us must point to epoch_count values;
 * out_look_angles must point to handle storage.
 */
enum SidereonStatus sidereon_tle_look_angles(const struct SidereonTle *tle,
                                             const struct SidereonGroundStation *station,
                                             const int64_t *epochs_unix_us,
                                             size_t epoch_count,
                                             struct SidereonLookAngles **out_look_angles);

/**
 * Copy parsed TLE metadata into *out_metadata.
 *
 * Safety: tle must be a live handle; out_metadata must point to a
 * SidereonTleMetadata.
 */
enum SidereonStatus sidereon_tle_metadata(const struct SidereonTle *tle,
                                          struct SidereonTleMetadata *out_metadata);

/**
 * Propagate a TLE over UTC unix-microsecond epochs. On success writes a newly
 * owned arc handle to *out_propagation. Release it with
 * sidereon_tle_propagation_free.
 *
 * Safety: tle must be a live handle; epochs_unix_us must point to epoch_count
 * int64_t values; out_propagation must point to handle storage.
 */
enum SidereonStatus sidereon_tle_propagate(const struct SidereonTle *tle,
                                           const int64_t *epochs_unix_us,
                                           size_t epoch_count,
                                           struct SidereonTlePropagation **out_propagation);

/**
 * Propagate one TLE at minutes since element epoch using a decay latch.
 *
 * The latch records the first decay-like SGP4 failure and rejects later
 * requests at the same or later epoch without returning a raw post-decay state.
 * Use sidereon_tle_propagate for the existing stateless UTC arc path.
 *
 * Safety: tle and latch must be live handles; out_state must point to a
 * SidereonTemeState.
 */
enum SidereonStatus sidereon_tle_propagate_with_decay_latch(const struct SidereonTle *tle,
                                                            double minutes_since_epoch,
                                                            struct SidereonSgp4DecayLatch *latch,
                                                            struct SidereonTemeState *out_state);

/**
 * Write the number of epochs in a TLE propagation arc to *out_count.
 *
 * Safety: propagation must be a live handle; out_count must point to a size_t.
 */
enum SidereonStatus sidereon_tle_propagation_epoch_count(const struct SidereonTlePropagation *propagation,
                                                         size_t *out_count);

/**
 * Release a TLE propagation handle. Null is a no-op. A non-null handle must
 * come from sidereon_tle_propagate and must be freed exactly once with this
 * function.
 *
 * Safety: propagation must be NULL or a live handle from
 * sidereon_tle_propagate. Passing a handle after it has already been freed is
 * invalid.
 */
void sidereon_tle_propagation_free(struct SidereonTlePropagation *propagation);

/**
 * Copy TEME states from a TLE propagation arc. Uses the variable-length output
 * contract documented at the top of the header.
 *
 * Safety: propagation must be a live handle; out must point to at least len
 * writable entries or be NULL when len is 0; out_written and out_required must
 * point to size_t values.
 */
enum SidereonStatus sidereon_tle_propagation_states(const struct SidereonTlePropagation *propagation,
                                                    struct SidereonTemeState *out,
                                                    size_t len,
                                                    size_t *out_written,
                                                    size_t *out_required);

/**
 * Re-encode the parsed TLE elements as two null-terminated TLE lines.
 *
 * Safety: tle must be a live handle; out_lines must point to a
 * SidereonTleLines.
 */
enum SidereonStatus sidereon_tle_to_lines(const struct SidereonTle *tle,
                                          struct SidereonTleLines *out_lines);

/**
 * Copy the base (all-rows) solve summary into *out_summary.
 *
 * Safety: report must be a live handle; out_summary must point to a
 * SidereonTrlsSummary.
 */
enum SidereonStatus sidereon_trls_drop_one_base_summary(const struct SidereonTrlsDropOne *report,
                                                        struct SidereonTrlsSummary *out_summary);

/**
 * Copy the per-row cost deltas (`drops[i].cost - base.cost`, length `m`) into
 * out: how much the optimum cost moves when each row is removed, the influence
 * signal for fault detection. Same variable-length output contract as
 * sidereon_trls_solution_x.
 *
 * Safety: report must be a live handle; out must point to at least len writable
 * doubles or be NULL when len is 0; out_written and out_required must point to
 * size_t values.
 */
enum SidereonStatus sidereon_trls_drop_one_cost_delta(const struct SidereonTrlsDropOne *report,
                                                      double *out,
                                                      size_t len,
                                                      size_t *out_written,
                                                      size_t *out_required);

/**
 * Write the number of dropped-row re-solves (equal to the residual count `m`)
 * into *out_count.
 *
 * Safety: report must be a live handle; out_count must point to a size_t.
 */
enum SidereonStatus sidereon_trls_drop_one_count(const struct SidereonTrlsDropOne *report,
                                                 size_t *out_count);

/**
 * Copy the summary of the re-solve with residual row `index` masked into
 * *out_summary. `index` must be less than sidereon_trls_drop_one_count.
 *
 * Safety: report must be a live handle; out_summary must point to a
 * SidereonTrlsSummary.
 */
enum SidereonStatus sidereon_trls_drop_one_drop_summary(const struct SidereonTrlsDropOne *report,
                                                        size_t index,
                                                        struct SidereonTrlsSummary *out_summary);

/**
 * Copy the solution vector of the re-solve with residual row `index` masked
 * into out. Same variable-length output contract as sidereon_trls_solution_x.
 *
 * Safety: report must be a live handle; out must point to at least len writable
 * doubles or be NULL when len is 0; out_written and out_required must point to
 * size_t values.
 */
enum SidereonStatus sidereon_trls_drop_one_drop_x(const struct SidereonTrlsDropOne *report,
                                                  size_t index,
                                                  double *out,
                                                  size_t len,
                                                  size_t *out_written,
                                                  size_t *out_required);

/**
 * Release a leave-one-out report handle. Null is a no-op.
 *
 * Safety: report must be NULL or a live handle from
 * sidereon_solve_data_problem_drop_one, freed exactly once.
 */
void sidereon_trls_drop_one_free(struct SidereonTrlsDropOne *report);

/**
 * Release a TRLS solution handle. Null is a no-op.
 *
 * Safety: sol must be NULL or a live handle from sidereon_solve_data_problem,
 * freed exactly once.
 */
void sidereon_trls_solution_free(struct SidereonTrlsSolution *sol);

/**
 * Copy the gradient `J^T f` (length `n`) at the solution into out. Same
 * variable-length output contract as sidereon_trls_solution_x.
 *
 * Safety: sol must be a live handle; out must point to at least len writable
 * doubles or be NULL when len is 0; out_written and out_required must point to
 * size_t values.
 */
enum SidereonStatus sidereon_trls_solution_gradient(const struct SidereonTrlsSolution *sol,
                                                    double *out,
                                                    size_t len,
                                                    size_t *out_written,
                                                    size_t *out_required);

/**
 * Copy the row-major `m`-by-`n` Jacobian at the solution into out (length
 * `m * n`). Same variable-length output contract as sidereon_trls_solution_x.
 *
 * Safety: sol must be a live handle; out must point to at least len writable
 * doubles or be NULL when len is 0; out_written and out_required must point to
 * size_t values.
 */
enum SidereonStatus sidereon_trls_solution_jacobian(const struct SidereonTrlsSolution *sol,
                                                    double *out,
                                                    size_t len,
                                                    size_t *out_written,
                                                    size_t *out_required);

/**
 * Copy the residual vector `fun` (length `m`) at the solution into out. Same
 * variable-length output contract as sidereon_trls_solution_x.
 *
 * Safety: sol must be a live handle; out must point to at least len writable
 * doubles or be NULL when len is 0; out_written and out_required must point to
 * size_t values.
 */
enum SidereonStatus sidereon_trls_solution_residuals(const struct SidereonTrlsSolution *sol,
                                                     double *out,
                                                     size_t len,
                                                     size_t *out_written,
                                                     size_t *out_required);

/**
 * Copy the scalar summary (cost, optimality, evaluation counts, status, shape)
 * into *out_summary.
 *
 * Safety: sol must be a live handle; out_summary must point to a
 * SidereonTrlsSummary.
 */
enum SidereonStatus sidereon_trls_solution_summary(const struct SidereonTrlsSolution *sol,
                                                   struct SidereonTrlsSummary *out_summary);

/**
 * Copy the solution vector `x` (length `n`) into out. Variable-length output
 * contract: pass out NULL with len 0 to query the count via *out_required.
 *
 * Safety: sol must be a live handle; out must point to at least len writable
 * doubles or be NULL when len is 0; out_written and out_required must point to
 * size_t values.
 */
enum SidereonStatus sidereon_trls_solution_x(const struct SidereonTrlsSolution *sol,
                                             double *out,
                                             size_t len,
                                             size_t *out_written,
                                             size_t *out_required);

/**
 * Hydrostatic and wet troposphere mapping factors at an elevation. Delegates to
 * sidereon_core::atmosphere::troposphere::tropo_mapping, selecting the model
 * (Niell) as a parameter to the core call rather than baking it into this name.
 * The epoch is a split Julian date in the given SidereonTimeScale.
 *
 * Safety: out must point to a SidereonMappingFactors.
 */
enum SidereonStatus sidereon_tropo_mapping_factors(double elevation_rad,
                                                   struct SidereonGeodetic receiver,
                                                   uint32_t scale,
                                                   double jd_whole,
                                                   double jd_fraction,
                                                   struct SidereonMappingFactors *out);

/**
 * Hydrostatic and wet mapping factors with typed low-elevation error detail.
 *
 * Safety: out must point to a SidereonMappingFactors; out_error must point to
 * a SidereonTropoMappingError.
 */
enum SidereonStatus sidereon_tropo_mapping_factors_checked(double elevation_rad,
                                                           struct SidereonGeodetic receiver,
                                                           uint32_t scale,
                                                           double jd_whole,
                                                           double jd_fraction,
                                                           struct SidereonMappingFactors *out,
                                                           struct SidereonTropoMappingError *out_error);

/**
 * Total slant troposphere delay in meters (Saastamoinen zenith, Niell mapping).
 * Delegates to sidereon_core::atmosphere::troposphere::tropo_slant, which
 * composes the zenith and mapping models internally.
 *
 * Safety: met must point to a SidereonMet; out must point to a double.
 */
enum SidereonStatus sidereon_tropo_slant_delay(double elevation_rad,
                                               struct SidereonGeodetic receiver,
                                               const struct SidereonMet *met,
                                               uint32_t scale,
                                               double jd_whole,
                                               double jd_fraction,
                                               double *out);

/**
 * Zenith hydrostatic and wet troposphere delay for a receiver and surface met.
 * Delegates to sidereon_core::atmosphere::troposphere::tropo_zenith, selecting
 * the model (Saastamoinen) as a parameter to the core call rather than baking it
 * into this name. receiver latitude/longitude are radians, height meters.
 *
 * Safety: receiver and met must point to their structs; out must point to a
 * SidereonZenithDelay.
 */
enum SidereonStatus sidereon_tropo_zenith_delay(struct SidereonGeodetic receiver,
                                                const struct SidereonMet *met,
                                                struct SidereonZenithDelay *out);

enum SidereonStatus sidereon_true_to_eccentric_anomaly(double true_anomaly_rad,
                                                       double eccentricity,
                                                       double *out);

enum SidereonStatus sidereon_true_to_mean_anomaly(double true_anomaly_rad,
                                                  double eccentricity,
                                                  double *out);

/**
 * Write whether a TT Julian date is inside UT1 coverage.
 *
 * Safety: out must point to a bool.
 */
enum SidereonStatus sidereon_ut1_coverage_covers_jd_tt(double jd_tt, bool *out);

/**
 * Write UT1 coverage metadata.
 *
 * Safety: out must point to a SidereonUt1CoverageInfo.
 */
enum SidereonStatus sidereon_ut1_coverage_info(struct SidereonUt1CoverageInfo *out);

/**
 * Copy UT1 coverage provenance text.
 *
 * Safety: out must point to out_len writable bytes or be NULL when out_len is
 * zero; out_written and out_required must point to size_t values.
 */
enum SidereonStatus sidereon_ut1_coverage_source(uint8_t *out,
                                                 size_t out_len,
                                                 size_t *out_written,
                                                 size_t *out_required);

/**
 * Apply the receiver-solution plausibility gates to an SPP solution handle.
 * Returns SIDEREON_STATUS_OK when the solution passes; otherwise returns
 * SIDEREON_STATUS_INVALID_ARGUMENT and records the failing gate. Delegates to
 * sidereon_core::quality::validate_receiver_solution.
 *
 * Safety: solution is a live SPP-solution handle; options points to a
 * SidereonSolutionValidationOptions.
 */
enum SidereonStatus sidereon_validate_receiver_solution(const struct SidereonSppSolution *solution,
                                                        const struct SidereonSolutionValidationOptions *options);

/**
 * Populate *out_options with the engine's default velocity solve options
 * (range-rate observable, light-time and Sagnac corrections on).
 *
 * Safety: out_options must point to a SidereonVelocityOptions.
 */
enum SidereonStatus sidereon_velocity_options_init(struct SidereonVelocityOptions *out_options);

/**
 * Write the receiver clock drift (seconds per second) to *out_drift.
 *
 * Safety: solution must be a live handle from sidereon_solve_velocity; out_drift
 * must point to a double.
 */
enum SidereonStatus sidereon_velocity_solution_clock_drift(const struct SidereonVelocitySolution *solution,
                                                           double *out_drift);

/**
 * Release a velocity solution handle from sidereon_solve_velocity. Passing NULL
 * is a no-op.
 *
 * Safety: solution must be NULL or a live handle from sidereon_solve_velocity
 * that has not already been freed.
 */
void sidereon_velocity_solution_free(struct SidereonVelocitySolution *solution);

/**
 * Copy the post-fit range-rate residuals (meters per second), in the same order
 * as sidereon_velocity_solution_used_sat_ids. Uses the variable-length output
 * contract documented at the top of the header.
 *
 * Safety: solution must be a live handle from sidereon_solve_velocity; out (when
 * non-NULL) must point to len writable doubles; out_written and out_required
 * must point to size_t.
 */
enum SidereonStatus sidereon_velocity_solution_residuals(const struct SidereonVelocitySolution *solution,
                                                         double *out,
                                                         size_t len,
                                                         size_t *out_written,
                                                         size_t *out_required);

/**
 * Write the receiver speed (meters per second) to *out_speed.
 *
 * Safety: solution must be a live handle from sidereon_solve_velocity; out_speed
 * must point to a double.
 */
enum SidereonStatus sidereon_velocity_solution_speed(const struct SidereonVelocitySolution *solution,
                                                     double *out_speed);

/**
 * Copy the unit-variance 4x4 state covariance in row-major order. The state is
 * [vx, vy, vz, clock_drift], where velocity is ECEF meters per second and clock
 * drift is seconds per second.
 *
 * Safety: solution must be a live handle from sidereon_solve_velocity or a
 * related velocity solve; out_m2 must point to len writable doubles and len
 * must be at least 16.
 */
enum SidereonStatus sidereon_velocity_solution_state_covariance(const struct SidereonVelocitySolution *solution,
                                                                double *out_m2,
                                                                size_t len);

/**
 * Write the number of satellites that contributed rows to *out_count.
 *
 * Safety: solution must be a live handle from sidereon_solve_velocity; out_count
 * must point to a size_t.
 */
enum SidereonStatus sidereon_velocity_solution_used_sat_count(const struct SidereonVelocitySolution *solution,
                                                              size_t *out_count);

/**
 * Copy the used-satellite tokens, in solve order. Uses the variable-length
 * output contract documented at the top of the header.
 *
 * Safety: solution must be a live handle from sidereon_solve_velocity; out (when
 * non-NULL) must point to len writable tokens; out_written and out_required must
 * point to size_t.
 */
enum SidereonStatus sidereon_velocity_solution_used_sat_ids(const struct SidereonVelocitySolution *solution,
                                                            struct SidereonSatelliteToken *out,
                                                            size_t len,
                                                            size_t *out_written,
                                                            size_t *out_required);

/**
 * Copy the receiver ECEF velocity (meters per second) into out_xyz (three
 * doubles).
 *
 * Safety: solution must be a live handle from sidereon_solve_velocity; out_xyz
 * must point to len writable doubles (len must be at least 3).
 */
enum SidereonStatus sidereon_velocity_solution_velocity(const struct SidereonVelocitySolution *solution,
                                                        double *out_xyz,
                                                        size_t len);

/**
 * Write the binding's semantic version components to the out-parameters. Any of
 * out_major, out_minor, or out_patch may be NULL to skip that component. These
 * match the SIDEREON_VERSION_* compile-time macros in this header.
 *
 * Safety: each non-null out pointer must point to a writable uint32_t.
 */
void sidereon_version(uint32_t *out_major, uint32_t *out_minor, uint32_t *out_patch);

/**
 * Return the binding's version as a static "MAJOR.MINOR.PATCH" string. The
 * pointer refers to static storage and must not be freed.
 */
const char *sidereon_version_string(void);

/**
 * Find the satellites of a constellation visible above min_elevation_deg from a
 * ground station at one UTC unix-microsecond instant. tles is an array of count
 * live TLE handles (each carrying its own opsmode from sidereon_tle_load); ids
 * is a parallel array of count null-terminated C strings, where ids[i] labels
 * tles[i] and becomes the result's catalog_number. Each id must be a non-empty
 * string of 1..=64 bytes (MAX_VISIBLE_ID_BYTES, excluding the NUL terminator);
 * an empty id, or one not NUL-terminated within 64 bytes, yields
 * SIDEREON_STATUS_INVALID_ARGUMENT, matching the other id-accepting entry
 * points. Per-satellite propagation or frame failures are skipped; the result
 * is sorted by elevation descending. On success writes a newly owned handle to
 * *out_visible. Release it with sidereon_visible_list_free.
 *
 * Safety: tles must point to count live TLE handle pointers; ids must point to
 * count null-terminated C-string pointers; station must point to a
 * SidereonGroundStation; out_visible must point to handle storage.
 */
enum SidereonStatus sidereon_visible_from_satellites(const struct SidereonTle *const *tles,
                                                     const char *const *ids,
                                                     size_t count,
                                                     const struct SidereonGroundStation *station,
                                                     int64_t epoch_unix_us,
                                                     double min_elevation_deg,
                                                     struct SidereonVisibleList **out_visible);

/**
 * Write the number of visible satellites in a visibility snapshot to
 * *out_count.
 *
 * Safety: visible must be a live handle; out_count must point to a size_t.
 */
enum SidereonStatus sidereon_visible_list_count(const struct SidereonVisibleList *visible,
                                                size_t *out_count);

/**
 * Release a constellation-visibility handle. Null is a no-op. A non-null handle
 * must come from sidereon_visible_from_satellites and must be freed exactly once
 * with this function.
 *
 * Safety: visible must be NULL or a live handle from
 * sidereon_visible_from_satellites. Passing a handle after it has already been
 * freed is invalid.
 */
void sidereon_visible_list_free(struct SidereonVisibleList *visible);

/**
 * Copy visible-satellite rows. Uses the variable-length output contract
 * documented at the top of the header.
 *
 * Safety: visible must be a live handle; out must point to at least len writable
 * entries or be NULL when len is 0; out_written and out_required must point to
 * size_t values.
 */
enum SidereonStatus sidereon_visible_list_values(const struct SidereonVisibleList *visible,
                                                 struct SidereonVisibleSatellite *out,
                                                 size_t len,
                                                 size_t *out_written,
                                                 size_t *out_required);

/**
 * Carrier wavelength in meters for a (system, band) pair. Delegates to
 * sidereon_core::frequencies::wavelength_m.
 *
 * Safety: out must point to a double.
 */
enum SidereonStatus sidereon_wavelength_m(uint32_t system, uint32_t band, double *out);

/**
 * Per-satellite inverse-variance weight for elevation/C-N0 entries. Writes one
 * value/present pair per input entry (see sidereon_sigmas for the contract).
 * Delegates to sidereon_core::quality::weight_vector.
 *
 * Safety: entries points to count SidereonWeightEntry; options to a
 * SidereonPseudorangeVarianceOptions; out_values to count doubles; out_present
 * to count bools.
 */
enum SidereonStatus sidereon_weight_vector(const struct SidereonWeightEntry *entries,
                                           size_t count,
                                           const struct SidereonPseudorangeVarianceOptions *options,
                                           double *out_values,
                                           bool *out_present);

/**
 * Convert a DTED tile tree and write memory-mappable terrain store bytes to
 * out_path. Store postings are orthometric heights in metres.
 *
 * Safety: root and out_path must be non-empty UTF-8 C strings.
 */
enum SidereonStatus sidereon_write_dted_tree_to_mmap_store(const char *root, const char *out_path);

/**
 * Compute Baarda w-test delta0 and lambda0 for one alpha and beta pair.
 *
 * Safety: out must point to writable SidereonWTestNoncentrality storage.
 */
enum SidereonStatus sidereon_wtest_noncentrality(double alpha,
                                                 double beta,
                                                 struct SidereonWTestNoncentrality *out);

